/*
 * tanf() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly tanf  (test_tanf_opt.elf)
 *   2. Linked with toolchain's default tanf        (test_tanf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static volatile float g_acc;

static void emit(float x)
{
#ifdef EN_PERF
    volatile float vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += tanf(vx);
#else
    float r = tanf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
#endif
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

#ifndef EN_PERF
/* ------------------------------------------------------------------ */
/* Representative 100-point test                                       */
/* ------------------------------------------------------------------ */
#endif

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0f);
    emit(-0.0f);
    emit_u(0x7fc00000u);  /* qNaN */
    emit_u(0x7f800001u);  /* sNaN */
    emit_u(0xffc00000u);  /* -qNaN */
    emit_u(0x7f800000u);  /* +Inf */
    emit_u(0xff800000u);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x00000001u);  /* min positive subnormal: 2^-149 */
    emit_u(0x80000001u);  /* min negative subnormal */
    emit_u(0x00400000u);  /* mid positive subnormal */
    emit_u(0x80400000u);  /* mid negative subnormal */
    emit_u(0x007fffffu);  /* max positive subnormal: just below FLT_MIN */
    emit_u(0x807fffffu);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(FLT_MIN);        /* smallest positive normal: 2^-126 = 0x00800000 */
    emit(-FLT_MIN);       /* smallest negative normal */
    emit_u(0x00800001u);  /* one ULP above FLT_MIN */
    emit(FLT_MAX);        /* largest positive normal: 0x7f7fffff */
    emit(-FLT_MAX);       /* largest negative normal */
    emit_u(0x7f7ffffeu);  /* one ULP below FLT_MAX */

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    emit_u(0x3f7fffffu);  /* one ULP below 1.0 */
    emit(1.0f);           /* 1.0 */
    emit_u(0x3f800001u);  /* one ULP above 1.0 */
    emit_u(0x3f7ffff0u);  /* a few ULPs below 1.0 */
    emit_u(0x3f800010u);  /* a few ULPs above 1.0 */
    emit(-1.0f);
    emit_u(0xbf7fffffu);  /* one ULP toward zero from -1.0 */
    emit_u(0xbf800001u);  /* one ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3effffffu);  /* one ULP below 0.5 */
    emit(0.5f);           /* 0.5 = 0x3f000000 */
    emit_u(0x3f000001u);  /* one ULP above 0.5 */
    emit_u(0x3fffffffu);  /* one ULP below 2.0 */
    emit(2.0f);           /* 2.0 = 0x40000000 */
    emit_u(0x40000001u);  /* one ULP above 2.0 */

    /* --- Section 6: Trig canonical constants (14) --- */
    emit_u(0x3f060a92u);  /* pi/6 ~ 0.5236 */
    emit_u(0x3f490fdbu);  /* pi/4 ~ 0.7854: tan = 1.0 */
    emit_u(0x3f860a92u);  /* pi/3 ~ 1.0472: tan = sqrt(3) */
    emit_u(0x3fc90fdbu);  /* pi/2 ~ 1.5708: tan -> +Inf */
    emit_u(0x40490fdbu);  /* pi ~ 3.1416: tan ~ 0 */
    emit_u(0x4096cbe4u);  /* 3*pi/2 ~ 4.7124: tan -> +Inf */
    emit_u(0x40c90fdbu);  /* 2*pi ~ 6.2832: tan ~ 0 */
    emit_u(0xbf060a92u);  /* -pi/6 */
    emit_u(0xbf490fdbu);  /* -pi/4: tan = -1.0 */
    emit_u(0xbfc90fdbu);  /* -pi/2 */
    emit_u(0xc0490fdbu);  /* -pi */
    emit_u(0x402d97c4u);  /* 2*pi/3 ~ 2.0944 */
    emit_u(0x4016cbe4u);  /* 3*pi/4 ~ 2.3562 */
    emit_u(0x402d9ab4u);  /* 5*pi/6 ~ 2.6180 */

    /* --- Section 7: Argument reduction stress - large floats (8) --- */
    emit_u(0x4dc90fdbu);  /* 100*pi as float */
    emit_u(0x501b74eeu);  /* ~1000*pi (approximate) */
    emit(1.0e7f);
    emit(1.0e10f);
    emit(-1.0e7f);
    emit(-1.0e10f);
    emit_u(0x4b000000u);  /* 2^23: mantissa precision boundary */
    emit_u(0x4b400000u);  /* 12582912.0 = 3*2^22, near a pi multiple */

    /* --- Section 8: ULP neighbors of key trig boundaries (15) --- */
    /* triplet around pi/2: tan -> +/-Inf */
    emit_u(0x3fc90fdau);  /* one ULP below pi/2 */
    emit_u(0x3fc90fdbu);  /* pi/2 */
    emit_u(0x3fc90fdcu);  /* one ULP above pi/2 */
    /* triplet around pi: tan ~ 0 */
    emit_u(0x40490fdau);  /* one ULP below pi */
    emit_u(0x40490fdbu);  /* pi */
    emit_u(0x40490fdcu);  /* one ULP above pi */
    /* triplet around 3*pi/2: tan -> +/-Inf */
    emit_u(0x4096cbe3u);  /* one ULP below 3*pi/2 */
    emit_u(0x4096cbe4u);  /* 3*pi/2 */
    emit_u(0x4096cbe5u);  /* one ULP above 3*pi/2 */
    /* triplet around 2*pi: tan ~ 0 */
    emit_u(0x40c90fdau);  /* one ULP below 2*pi */
    emit_u(0x40c90fdbu);  /* 2*pi */
    emit_u(0x40c90fdcu);  /* one ULP above 2*pi */
    /* triplet around -pi/2: tan -> +/-Inf */
    emit_u(0xbfc90fdau);  /* one ULP below -pi/2 (toward zero) */
    emit_u(0xbfc90fdbu);  /* -pi/2 */
    emit_u(0xbfc90fdcu);  /* one ULP away from zero from -pi/2 */

    /* --- Section 9: Small-argument fast-path thresholds (8) --- */
    /* tan(x) ~ x for small x; test at power-of-2 boundaries */
    emit_u(0x3a800000u);  /* 2^-12 */
    emit_u(0xba800000u);  /* -2^-12 */
    emit_u(0x3d000000u);  /* 2^-6 */
    emit_u(0xbd000000u);  /* -2^-6 */
    emit_u(0x3b800000u);  /* 2^-9 */
    emit_u(0xbb800000u);  /* -2^-9 */
    emit_u(0x33800000u);  /* 2^-24: near ULP of 1.0 */
    emit_u(0xb3800000u);  /* -2^-24 */

    /* --- Section 10: Polynomial branch and hard reduction cases (22) --- */
    /* triplet around pi/8: midpoint of primary polynomial interval */
    emit_u(0x3ec90fdau);  /* one ULP below pi/8 */
    emit_u(0x3ec90fdbu);  /* pi/8 */
    emit_u(0x3ec90fdcu);  /* one ULP above pi/8 */
    /* triplet around pi/4: tan = 1.0, polynomial switchover */
    emit_u(0x3f490fdau);  /* one ULP below pi/4 */
    emit_u(0x3f490fdbu);  /* pi/4 */
    emit_u(0x3f490fdcu);  /* one ULP above pi/4 */
    /* triplet around 3*pi/8: cos-path reconstruction */
    emit_u(0x3f96cbe3u);  /* one ULP below 3*pi/8 */
    emit_u(0x3f96cbe4u);  /* 3*pi/8 */
    emit_u(0x3f96cbe5u);  /* one ULP above 3*pi/8 */
    /* k*pi: tan ~ 0, catastrophic cancellation */
    emit_u(0x40c90fdbu);  /* 2*pi ~ 6.2832 (already in sec 6 but different context) - use 3*pi */
    emit_u(0xc0c90fdbu);  /* -2*pi */
    emit_u(0x4116cbe4u);  /* 3*pi ~ 9.4248 */
    emit_u(0xc116cbe4u);  /* -3*pi */
    emit_u(0x41490fdbu);  /* 4*pi ~ 12.566 */
    emit_u(0x41c90fdbu);  /* 5*pi ~ 15.708 */
    /* odd half-multiples: tan -> +/-Inf after reduction */
    emit_u(0x413c9fd4u);  /* 5*pi/2 ~ 7.854 */
    emit_u(0x415fdbb4u);  /* 7*pi/2 ~ 10.996 */
    emit_u(0xc13c9fd4u);  /* -5*pi/2 */
    /* near-asymptote stress: just off pi/2 multiples by known small offsets */
    emit(1.5707f);        /* slightly less than pi/2 */
    emit(1.5708f);        /* slightly more than pi/2 */
    emit(4.7123f);        /* slightly less than 3*pi/2 */
    emit(4.7125f);        /* slightly more than 3*pi/2 */
}

/* 7. Sweep [0, 4*pi] and [-4*pi, 0] in 200 steps each */
#ifndef EN_PERF
static void test_sweep(void)
{
    float hi = 4.0f * 3.14159265358979323846f;
    int nsteps = 200;
    float step = hi / (float)nsteps;

    /* [0, 4*pi] */
    for (int i = 0; i <= nsteps; i++)
        emit((float)i * step);

    /* [-4*pi, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (float)i * step);
}

/* 8. Sample [0, pi/4] every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    uint32_t end = 0x3f490fdbu; /* pi/4 */
    for (uint32_t b = 0; b <= end; b += 4194304)
        emit_u(b);
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf g_acc: %08lx\n", (unsigned long)f2u((float)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}
